var e=[{id:`L2_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`하, 하하!`,JPN:`は、はは！`,ENG:`Ha! Haha!`,TWN:`呼，呼呼！`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`봤어? 훈련한 보람이 있지?`,JPN:`見た？　訓練した甲斐があっただろ？`,ENG:`Did you see that? I knew all that training was gonna pay off.`,TWN:`看到沒？這就是訓練的成果！`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`……시뮬레이션 결과, 뒤를 노리던 용병을 내가 안 막아 줬으면, 도로시는 당했어.`,JPN:`……シミュレーションの結果、後ろを狙っていた傭兵をワタシが食い止めなかったら、ドロシーはやられた。`,ENG:`...Simulation results show that if I hadn't stopped that mercenary trying to get us in the back, Dorothy, you would have been hurt.`,TWN:`……根據模擬結果，要是我沒擋住你身後的傭兵，你恐怕早已中招。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_PRIDE`}}}},{id:`L7_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`이거 금메달 땄을 때만큼이나 짜릿한데?`,JPN:`これ、金メダル獲った時みたいにビリビリするんだけど！`,ENG:`This is just as exciting as when I won a gold medal!`,TWN:`感覺就跟奪金一樣痛快欸！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_PRIDE`}}}},{id:`L8_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`안 들리는 척하기는.`,JPN:`聞こえないふりしてる。`,ENG:`I know you can hear me.`,TWN:`還裝沒聽到。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L10_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`이… 무슨…….`,JPN:`この……この……！`,ENG:`What in the...!`,TWN:`嘖…搞什麼……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`어딜 가려고?`,JPN:`どこに行くの？`,ENG:`Going somewhere?`,TWN:`你想逃去哪？`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L16_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`저리 가지 못해?!`,JPN:`近づかないで！！`,ENG:`Get away from me!`,TWN:`給我滾開！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`응. 보채지 않아도 보내줄 거야.`,JPN:`うん。せかさなくても行かせてあげるよ。`,ENG:`Okay. But you don’t have to fuss. I’m going to let you go.`,TWN:`嗯，不用你說，我也不會攔你。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`잠시 기다려.`,JPN:`ちょっと待っててね。`,ENG:`Just hold on.`,TWN:`等我一下。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`꺄악! 뜨겁……`,JPN:`きゃあっ！　熱……`,ENG:`Kyaah! It’s...`,TWN:`啊！好燙……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:` 지 않네?`,JPN:`くないわね？`,ENG:` not burning?`,TWN:`怎麼不會燙？`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`하아…….`,JPN:`はあ……`,ENG:`*Sigh...*`,TWN:`呼……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`루루! 괜찮아?`,JPN:`ルル！　大丈夫？`,ENG:`Lulu! Are you okay?`,TWN:`露露！你沒事吧？`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`후후. 불꽃을 던지길래 불이라도 내려나 했는데. 그것도 실패한 모양이구나.`,JPN:`ふふ。炎を投げるから火でも点けるつもりなのかと思ったら。それも失敗したようね。`,ENG:`Hu hu. I thought she was going to burn me. However, it appears that she failed.`,TWN:`呵呵，丟個火球過來，我還以為會燒起來呢，看來是失敗的樣子？`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`더는 놀아줄 시간이 없을 것 같으니, 다음을 기약하도록 하지.`,JPN:`もう遊んであげる時間はなさそうだから、今度またにするわ。`,ENG:`I don’t have time to play with you all. So until next time...`,TWN:`我沒時間陪你們玩了，下次再會囉～`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};